import React, { useState } from "react";
import axios from "axios";

export default function CampaignCard({ type }) {
  const [message, setMessage] = useState("");
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  const sendCampaign = async () => {
    if (!message || !file) {
      alert("Please provide a message and upload a recipients file");
      return;
    }

    // Check file type
    if (!file.name.endsWith('.csv')) {
      alert("Please upload a CSV file");
      return;
    }

    setLoading(true);
    try {
      const token = localStorage.getItem("token");
      const formData = new FormData();
      formData.append('name', `${type} Campaign`);
      formData.append('type', type.toLowerCase());
      formData.append('message', message);
      formData.append('recipientsFile', file);

      const res = await axios.post(
        "http://localhost:5000/api/campaigns",
        formData,
        {
          headers: { 
            Authorization: `Bearer ${token}`,
            'Content-Type': 'multipart/form-data'
          }
        }
      );
      
      alert(`Campaign sent successfully to ${res.data.recipients} recipients!`);
      setMessage("");
      setFile(null);
      // Reset file input
      document.getElementById('file-input').value = '';
    } catch (error) {
      console.error("Error sending campaign:", error);
      alert("Failed to send campaign: " + (error.response?.data?.message || error.message));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white p-6 rounded shadow">
      <h2 className="text-lg font-bold mb-4">{type} Campaign</h2>
      
      <div className="mb-3">
        <label className="block text-sm font-medium mb-1">Recipients File (CSV)</label>
        <input
          id="file-input"
          type="file"
          accept=".csv"
          onChange={handleFileChange}
          className="border p-2 w-full"
        />
        <p className="text-xs text-gray-500 mt-1">
          Upload a CSV file with columns: name, phone
        </p>
      </div>

      <div className="mb-3">
        <label className="block text-sm font-medium mb-1">Message Template</label>
        <textarea
          className="border p-2 w-full"
          placeholder="Enter your message here..."
          rows={4}
          value={message}
          onChange={(e) => setMessage(e.target.value)}
        />
      </div>

      {file && (
        <div className="mb-3 p-2 bg-gray-50 rounded">
          <p className="text-sm text-gray-600">
            Selected file: {file.name}
          </p>
        </div>
      )}

      <button
        className={`w-full py-2 rounded text-white ${
          loading
            ? "bg-gray-400 cursor-not-allowed"
            : "bg-green-500 hover:bg-green-600"
        }`}
        onClick={sendCampaign}
        disabled={loading}
      >
        {loading ? "Sending..." : "Send Campaign"}
      </button>
    </div>
  );
}
